        new object[] { "SLH-DSA-SHA2-256f", 46, "SHA3-384", "2B4B3523117C34AD3A09695B9DA80FA2B3AFBBD095D1F0053F30793AA842643ACF1C1EFC06FB085BD0DCA09D56572EE0AC4A327345E6EE371B0D410791C8CEC5191E0746FF35F7F2248EF5DDF530CFE97AC6C4836D658C0160AC1EF302D0A5A4BFC2E814E69FC197E1EF8B8C48DEDB0BEFEDC7D9241B4A41C28A568E744A6824", "B8", "F82FA7DD11926BC60C6A88C3465B715E655BCE3AC7148F94E811E015645CC60ACACDBFD480D7CE56CDEE1FC4C49B4A2F9D4CACAE08860C", "" },
        // SLH-DSA-SHAKE-128f, ACVP sigGen (preHash, deterministic) tcId 75, PH = SHA2-384
        new object[] { "SLH-DSA-SHAKE-128f", 75, "SHA2-384", "CD8419300D3B268C5781FFC86228F2A5603B8AA7955DC8E9C6726349C412E6CFF5A0D4707E478401864FE104990614C91F938A84231E30284346F84776A607E3", "8B", "E9F1B2EA5FEF4FEC862C055B398B576F7FFC8940D0A4A79AFE57A8A41416D715A9C42BA193555AB5578E7F37EDBC912A7F3AF7DFFF5CEE14924540BAA4A77A0564F317CBB5D7AA77DB889CBEB83AE03E114D4B8E1C3C09C18FE1793DCD363DF34D3871CEFBA377CBC9141B081D7EF50B830DF0E29AC73ED6C2136E2CA274", "" },
