        new object[] { "SLH-DSA-SHAKE-256f", 114, "SHA2-512/224", "DCC8C814F52671C8F9235FAE8A81A4E337890378FFDB39158CA09AA64082F5734C78AB73357789D114F9D9A67DF5803DBBA9ECEDA7BF2073BC46EEB887AEA393C74811772EB69AAAB9354AD394B76BC8DB0B7C9F8E17C45EF47F0154D46BFE71C67C3E1504759923CC5BB4B5CA537356E2AA248556BF2946263FC9C68F66FEBE", "", "", "" },
