        new object[] { "SLH-DSA-SHAKE-128s", 225, "SHA3-256", "C98073E11F60733E69FF893A3A9803284DBFB2667173FF9DC090DD930CFD70257DDDD01E72520F364D9786BC7796AECF0D6E981595D5963B5F17B3D8202F38B5", "8F", "5D25D2C0454B26E7E22DBFEE43B8DC22F3AF81463698DCF0C301981697608C8F555B19A16D32C0A2FA0B0970CF86C06FC4DB8E28F02D2377C740F305EE20F3EC9E", "" },
