    private static readonly object[] SigVerVectors =
    [
        // SLH-DSA-SHA2-128f, ACVP sigVer (preHash) tcId 25 (valid signature and message - signature should verify successfully), PH = SHA2-256
        new object[] { "SLH-DSA-SHA2-128f", 25, true, "SHA2-256", "D71D4BCED672A7C2589C74B2B070EBDD826E8B208135B6C5EBBB946591F481B0", "", "7C5E2104790D81CEBF01E26DB13E5C00EF134B9056C56003B53A14028226F22AA16A1DA4245AFCA30E75B81E358732A4C65C17C57E3C229903455E76B18F44772018F4E4", "" },
        // SLH-DSA-SHA2-128f, ACVP sigVer (preHash) tcId 17 (modified signature - R), PH = SHA3-256
        new object[] { "SLH-DSA-SHA2-128f", 17, false, "SHA3-256", "E52D498FB26FE759B398B8F721C9E438B335F07E085685F6FF82FB45C4B22AD6", "F4", "356784FD1F1A94AB7E791EBFED6B4CA2FA59E54D38739992405ABE57D1DB6BD5B550BF4B8954036B5734DF10C7AAEED7B5FF3E06543842", "" },
        // SLH-DSA-SHAKE-128f, ACVP sigVer (preHash) tcId 107 (valid signature and message - signature should verify successfully), PH = SHA3-512
        new object[] { "SLH-DSA-SHAKE-128f", 107, true, "SHA3-512", "0741C7887FF1BE55F5D2343782CDB118649B063024A5577D259B0EF4C2F84433", "", "", "" },
        // SLH-DSA-SHAKE-128f, ACVP sigVer (preHash) tcId 101 (modified signature - SIGFORS), PH = SHA3-256
        new object[] { "SLH-DSA-SHAKE-128f", 101, false, "SHA3-256", "4F79A18F8DBDFA6D18641DDCC8CB3B4F41467624D44C9D1625BD94EAD9779024", "69", "", "" },
    ];

    [Test]
    [TestCaseSource(nameof(SigGenVectors))]
    public void SigGenPreHashDeterministic_MatchesAcvpVector(string parameterSet, int tcId, string hashAlg,
        string skHex, string messageHex, string contextHex, string signatureHex)
    {
        SlhDsaParams p = PreHashTestUtil.SlhDsaParamsFor(parameterSet);
        (byte[] digest, string oid) = PreHashTestUtil.ComputeDigest(hashAlg, PreHashTestUtil.FromHex(messageHex));
        byte[] sk = PreHashTestUtil.FromHex(skHex);

        byte[] prefix = new byte[PreHash.MaxPrefixBytes];
        int prefixLength = PreHash.BuildPrefix(PreHashTestUtil.FromHex(contextHex), oid, prefix);

        // Deterministic signing uses opt_rand = PK.seed (embedded in sk at offset 2n).
        byte[] signature = new byte[p.SignatureBytes];
        SlhDsaCore.Sign(p, sk, prefix.AsSpan(0, prefixLength), digest, sk.AsSpan(2 * p.N, p.N), signature);

        Assert.That(signature, Is.EqualTo(PreHashTestUtil.FromHex(signatureHex)),
            $"{parameterSet} tcId {tcId} (PH = {hashAlg}): signature mismatch.");
    }

    [Test]
    [TestCaseSource(nameof(SigVerVectors))]
    public void SigVerPreHash_MatchesAcvpVector(string parameterSet, int tcId, bool expectedValid, string hashAlg,
        string pkHex, string messageHex, string contextHex, string signatureHex)
    {
        using var verifier = CryptoHives.Foundation.Security.Cryptography.Dsa.SlhDsa.ImportPublicKey(
            PreHashTestUtil.SlhDsaAlgorithmFor(parameterSet), PreHashTestUtil.FromHex(pkHex));
        (byte[] digest, string oid) = PreHashTestUtil.ComputeDigest(hashAlg, PreHashTestUtil.FromHex(messageHex));

        bool valid = verifier.VerifyPreHash(digest, PreHashTestUtil.FromHex(signatureHex), oid, PreHashTestUtil.FromHex(contextHex));

        Assert.That(valid, Is.EqualTo(expectedValid), $"{parameterSet} tcId {tcId} (PH = {hashAlg}): verification result mismatch.");
    }
}
